import React, { useEffect, useState } from "react";
import api from "../services/axios";
import WebSocketComponent from "../components/WebSocketComponent";

function Dashboard() {
  const [breaches, setBreaches] = useState([]);
  const [auditResults, setAuditResults] = useState([]);
  const [anomalies, setAnomalies] = useState([]);
  const [loading, setLoading] = useState(true);
  const [auditLoading, setAuditLoading] = useState(false);
  const [threatLoading, setThreatLoading] = useState(false);
  const [error, setError] = useState(null);
  const [activeTab, setActiveTab] = useState("overview");

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      setLoading(true);
      const [breachesRes] = await Promise.all([
        api.get("/breaches/"),
      ]);
      setBreaches(breachesRes.data);
    } catch (err) {
      console.error("Error fetching data", err);
      setError("Failed to load data. Please try again later.");
    } finally {
      setLoading(false);
    }
  };

  const runCloudAudit = async () => {
    setAuditLoading(true);
    try {
      const response = await api.get("/cloud-audits/audit/");
      setAuditResults(response.data);
      alert("Cloud audit completed!");
    } catch (err) {
      console.error("Error running audit", err);
      alert("Failed to run cloud audit. Check console for details.");
    } finally {
      setAuditLoading(false);
    }
  };

  const runThreatDetection = async () => {
    setThreatLoading(true);
    try {
      const response = await api.get("/ml-model/threat-detection/");
      setAnomalies(response.data.anomalies || []);
      alert("Threat detection completed!");
    } catch (err) {
      console.error("Error running threat detection", err);
      alert("Failed to run threat detection. Check console for details.");
    } finally {
      setThreatLoading(false);
    }
  };

  const getStatusColor = (status) => {
    if (status === "open" || status === "critical") return "#e74c3c";
    if (status === "closed" || status === "resolved") return "#27ae60";
    return "#f39c12";
  };

  const stats = {
    totalBreaches: breaches.length,
    openBreaches: breaches.filter(b => b.status === "open").length,
    closedBreaches: breaches.filter(b => b.status === "closed").length,
  };

  if (loading) {
    return (
      <div className="dashboard-loading">
        <div className="spinner"></div>
        <p>Loading dashboard...</p>
      </div>
    );
  }

  return (
    <div className="dashboard">
      <div className="dashboard-header">
        <h1>Security Dashboard</h1>
        <p>Monitor your cloud infrastructure security in real-time</p>
      </div>

      <div className="dashboard-tabs">
        <button
          className={`tab ${activeTab === "overview" ? "active" : ""}`}
          onClick={() => setActiveTab("overview")}
        >
          Overview
        </button>
        <button
          className={`tab ${activeTab === "audits" ? "active" : ""}`}
          onClick={() => setActiveTab("audits")}
        >
          Cloud Audits
        </button>
        <button
          className={`tab ${activeTab === "threats" ? "active" : ""}`}
          onClick={() => setActiveTab("threats")}
        >
          Threat Detection
        </button>
        <button
          className={`tab ${activeTab === "alerts" ? "active" : ""}`}
          onClick={() => setActiveTab("alerts")}
        >
          Real-Time Alerts
        </button>
      </div>

      {error && <div className="error-message">{error}</div>}

      {/* Overview Tab */}
      {activeTab === "overview" && (
        <div className="tab-content">
          <div className="stats-grid">
            <div className="stat-card">
              <div className="stat-icon">🛡️</div>
              <div className="stat-info">
                <h3>{stats.totalBreaches}</h3>
                <p>Total Incidents</p>
              </div>
            </div>
            <div className="stat-card stat-warning">
              <div className="stat-icon">⚠️</div>
              <div className="stat-info">
                <h3>{stats.openBreaches}</h3>
                <p>Open Issues</p>
              </div>
            </div>
            <div className="stat-card stat-success">
              <div className="stat-icon">✅</div>
              <div className="stat-info">
                <h3>{stats.closedBreaches}</h3>
                <p>Resolved</p>
              </div>
            </div>
            <div className="stat-card">
              <div className="stat-icon">📊</div>
              <div className="stat-info">
                <h3>{stats.totalBreaches > 0 ? Math.round((stats.closedBreaches / stats.totalBreaches) * 100) : 100}%</h3>
                <p>Resolution Rate</p>
              </div>
            </div>
          </div>

          <div className="dashboard-sections">
            <div className="section-card">
              <h3>Recent Incidents</h3>
              {breaches.length === 0 ? (
                <p className="empty-state">No incidents found</p>
              ) : (
                <ul className="incident-list">
                  {breaches.slice(0, 5).map((breach) => (
                    <li key={breach.id} className="incident-item">
                      <span className="incident-name">{breach.name}</span>
                      <span
                        className="incident-status"
                        style={{ color: getStatusColor(breach.status) }}
                      >
                        {breach.status}
                      </span>
                    </li>
                  ))}
                </ul>
              )}
            </div>

            <div className="section-card">
              <h3>Quick Actions</h3>
              <div className="quick-actions">
                <button
                  className="action-btn"
                  onClick={runCloudAudit}
                  disabled={auditLoading}
                >
                  {auditLoading ? "Running..." : "Run Cloud Audit"}
                </button>
                <button
                  className="action-btn"
                  onClick={runThreatDetection}
                  disabled={threatLoading}
                >
                  {threatLoading ? "Detecting..." : "Detect Threats"}
                </button>
                <button
                  className="action-btn"
                  onClick={() => setActiveTab("audits")}
                >
                  View Audit Results
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Cloud Audits Tab */}
      {activeTab === "audits" && (
        <div className="tab-content">
          <div className="section-card">
            <div className="section-header">
              <h3>Cloud Security Audits</h3>
              <button
                className="btn btn-primary"
                onClick={runCloudAudit}
                disabled={auditLoading}
              >
                {auditLoading ? "Running Audit..." : "Run New Audit"}
              </button>
            </div>
            <p className="section-description">
              Check your AWS infrastructure for security vulnerabilities including S3 buckets,
              IAM roles, KMS encryption, and CloudTrail logging.
            </p>
            {auditResults.message ? (
              <div className="audit-result success">
                <p>{auditResults.message}</p>
              </div>
            ) : (
              <p className="empty-state">No audit results yet. Run an audit to see results.</p>
            )}
          </div>
        </div>
      )}

      {/* Threat Detection Tab */}
      {activeTab === "threats" && (
        <div className="tab-content">
          <div className="section-card">
            <div className="section-header">
              <h3>AI Threat Detection</h3>
              <button
                className="btn btn-primary"
                onClick={runThreatDetection}
                disabled={threatLoading}
              >
                {threatLoading ? "Analyzing..." : "Run Detection"}
              </button>
            </div>
            <p className="section-description">
              Uses Isolation Forest machine learning algorithm to detect anomalies in user behavior,
              login patterns, and suspicious activities.
            </p>
            {anomalies.length > 0 ? (
              <div className="anomalies-list">
                {anomalies.map((anomaly, index) => (
                  <div key={index} className="anomaly-card">
                    <div className="anomaly-header">
                      <span className="anomaly-icon">🤖</span>
                      <span className="anomaly-title">Anomaly Detected</span>
                    </div>
                    <pre>{JSON.stringify(anomaly, null, 2)}</pre>
                  </div>
                ))}
              </div>
            ) : (
              <p className="empty-state">No anomalies detected. Your system appears secure.</p>
            )}
          </div>
        </div>
      )}

      {/* Real-Time Alerts Tab */}
      {activeTab === "alerts" && (
        <div className="tab-content">
          <div className="section-card">
            <h3>Real-Time Threat Alerts</h3>
            <p className="section-description">
              Receive instant notifications when security threats are detected.
              This feature uses WebSocket for real-time communication.
            </p>
            <WebSocketComponent />
          </div>
        </div>
      )}
    </div>
  );
}

export default Dashboard;
